import (
	"flag"
	"fmt"
	"os"

	"github.com/volcano-sh/agentcube/pkg/picod"
	"k8s.io/klog/v2"
)

func main() {
	port := flag.Int("port", 8080, "HTTP server port")
	workspace := flag.String("workspace", "", "Workspace directory")
	klog.InitFlags(nil)
	flag.Parse()

	cfg := picod.Config{
		Port:      *port,
		Workspace: *workspace,
	}

	server := picod.NewServer(cfg)

	klog.Infof("Starting PicoD on port %d", *port)
	if err := server.Run(); err != nil {
		klog.Fatalf("Server error: %v", err)
	}
}

