func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, ErrorResponse{Message: "authorization header required"})
			c.Abort()
			return
		}

		if len(authHeader) < 7 || authHeader[:7] != "Bearer " {
			c.JSON(http.StatusUnauthorized, ErrorResponse{Message: "invalid authorization header"})
			c.Abort()
			return
		}

		token := authHeader[7:]
		authenticated, _, _, ok := s.tokenCache.Get(token)
		if !ok || !authenticated {
			c.JSON(http.StatusUnauthorized, ErrorResponse{Message: "invalid token"})
			c.Abort()
			return
		}

		c.Next()
	}
}

func (s *Server) handleAgentRuntimeCreate(c *gin.Context) {
	var req types.CreateSandboxRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: err.Error()})
		return
	}

	if err := req.Validate(); err != nil {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: err.Error()})
		return
	}

	sessionID := uuid.New().String()
	sandboxID := fmt.Sprintf("sandbox-%s", uuid.New().String()[:8])

	sandbox := &types.SandboxInfo{
		Kind:             types.AgentRuntimeKind,
		SandboxID:        sandboxID,
		SandboxNamespace: req.Namespace,
		Name:             req.Name,
		SessionID:        sessionID,
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(DefaultSandboxTTL),
		Status:           "pending",
	}

	if err := s.storeClient.StoreSandbox(c.Request.Context(), sandbox); err != nil {
		klog.Errorf("Failed to store sandbox: %v", err)
		c.JSON(http.StatusInternalServerError, ErrorResponse{Message: "failed to create session"})
		return
	}

	resp := &types.CreateSandboxResponse{
		SessionID:   sessionID,
		SandboxID:   sandboxID,
		SandboxName: sandboxID,
		EntryPoints: []types.SandboxEntryPoint{
			{
				Path:     "/",
				Protocol: "http",
				Endpoint: fmt.Sprintf("http://%s.%s.svc.cluster.local:8080", sandboxID, req.Namespace),
			},
		},
	}

	c.JSON(http.StatusOK, resp)
}

