func (s *Server) handleDeleteSandbox(c *gin.Context) {
	sessionID := c.Param("sessionId")
	if sessionID == "" {
		c.JSON(http.StatusBadRequest, ErrorResponse{Message: "session_id is required"})
		return
	}

	if err := s.storeClient.DeleteSandboxBySessionID(c.Request.Context(), sessionID); err != nil {
